import{_ as t,o as a,c as s,ag as i}from"./chunks/framework.DLWhSH9p.js";const k=JSON.parse('{"title":"AI Providers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai-providers.md","filePath":"guide/ai-providers.md"}'),l={name:"guide/ai-providers.md"};function o(d,e,r,n,h,p){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="ai-providers" tabindex="-1">AI Providers <a class="header-anchor" href="#ai-providers" aria-label="Permalink to &quot;AI Providers&quot;">​</a></h1><p>CRAFT Studio supports three AI providers. All can be active at once — pick per-request from the model dropdown. API keys are <strong>per-user</strong> and stored encrypted on the server — set them in <strong>Avatar menu → API Keys</strong>.</p><h2 id="gemini-google" tabindex="-1">Gemini (Google) <a class="header-anchor" href="#gemini-google" aria-label="Permalink to &quot;Gemini (Google)&quot;">​</a></h2><p>Paste a Gemini API key in the API Keys modal (<code>GEMINI_API_KEY</code>).</p><p>Get a key at <a href="https://ai.google.dev/gemini-api/docs/api-key" target="_blank" rel="noreferrer">ai.google.dev</a>.</p><p><strong>Characteristics</strong></p><ul><li>Streams responses token-by-token (real-time)</li><li>Reliable with standard API keys</li><li>Good for quick iterations</li><li>Free tier is usually enough to explore the studio</li></ul><h2 id="claude-anthropic" tabindex="-1">Claude (Anthropic) <a class="header-anchor" href="#claude-anthropic" aria-label="Permalink to &quot;Claude (Anthropic)&quot;">​</a></h2><p>Claude uses the Agent SDK and authenticates via a <strong>long-lived OAuth token</strong>, not a paid API key. Generate a token at <a href="https://claude.ai/settings/tokens" target="_blank" rel="noreferrer">claude.ai/settings/tokens</a> and paste it into the API Keys modal as <code>CLAUDE_CODE_OAUTH_TOKEN</code>.</p><div class="tip custom-block"><p class="custom-block-title">No API credits needed</p><p>Unlike the raw Anthropic API, the Agent SDK uses your Claude subscription. Premium users get the full Claude model family (Opus, Sonnet, Haiku) plus MCP tool access when a token is saved.</p></div><p><strong>Characteristics</strong></p><ul><li>The SDK may use MCP research tools (storytelling, comedy, etc.) during multi-turn generation</li><li>Responses arrive as a single block (not streamed) — intermediate planning is filtered out</li><li>Excellent for complex script writing and fact-checking</li></ul><h2 id="ollama-local-llm" tabindex="-1">Ollama (Local LLM) <a class="header-anchor" href="#ollama-local-llm" aria-label="Permalink to &quot;Ollama (Local LLM)&quot;">​</a></h2><p>Ollama runs models on your local GPU — no API key needed, no internet after the model is pulled. CRAFT picks up whatever models are loaded on the Ollama server it&#39;s pointed at; the model picker shows them automatically in an &quot;Ollama (Free)&quot; optgroup. Available whenever the Ollama service is reachable (GPU services are optional; see the deployment docs for your administrator).</p><div class="tip custom-block"><p class="custom-block-title">Auto-pull on first boot</p><p>The Ollama container auto-pulls <code>qwen2.5:1.5b</code> if no models exist when it starts, so a fresh deploy boots with at least one usable local model. The recommended default is <code>qwen2.5:7b</code> (~4.7 GB, 128 k context) for script writing — pull it once and it stays available.</p></div><h3 id="pulling-additional-models" tabindex="-1">Pulling additional models <a class="header-anchor" href="#pulling-additional-models" aria-label="Permalink to &quot;Pulling additional models&quot;">​</a></h3><p>There&#39;s no in-app pull UI today — model management is an operator task. Pick whichever path matches your deploy:</p><p><strong>k3s / Helm</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy/craft-ollama</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ollama</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen2.5:7b</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy/craft-ollama</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ollama</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p><strong>docker compose</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ollama</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ollama</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen2.5:7b</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ollama</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ollama</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p><strong>Local Ollama (dev outside Docker)</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ollama</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen2.5:7b</span></span></code></pre></div><p>Pulled models persist across container restarts as long as the Ollama volume is mounted (<code>./models/ollama:/root/.ollama</code> in compose, the <code>ollama-models</code> PVC in Helm).</p><h3 id="suggested-models" tabindex="-1">Suggested models <a class="header-anchor" href="#suggested-models" aria-label="Permalink to &quot;Suggested models&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Size</th><th>Best for</th></tr></thead><tbody><tr><td><code>qwen2.5:7b</code></td><td>~4.7 GB</td><td><strong>Recommended default</strong> — script writing, 128 k context</td></tr><tr><td><code>qwen2.5-coder:14b</code></td><td>~9 GB</td><td>Code-aware scripts, reasoning</td></tr><tr><td><code>deepseek-r1:14b</code></td><td>~9 GB</td><td>Reasoning, fact-heavy scripts</td></tr><tr><td><code>llama3.1:8b</code></td><td>~5 GB</td><td>General purpose (lower VRAM)</td></tr><tr><td><code>qwen2.5:1.5b</code></td><td>~986 MB</td><td>Auto-pulled fallback — fast but limited output</td></tr></tbody></table><h3 id="characteristics" tabindex="-1">Characteristics <a class="header-anchor" href="#characteristics" aria-label="Permalink to &quot;Characteristics&quot;">​</a></h3><ul><li>Streams responses token-by-token (like Gemini)</li><li>Fully offline once the model is downloaded</li><li>GPU required for usable speed</li><li>Available to every user — Ollama models appear in the dropdown&#39;s &quot;Ollama (Free)&quot; optgroup whether or not the user has any API keys configured</li></ul><div class="tip custom-block"><p class="custom-block-title">VRAM requirements</p><p>14 B parameter models need ~10 GB VRAM. If you have 8 GB or less, pick 7 B / 8 B variants instead.</p></div><h2 id="model-selection" tabindex="-1">Model selection <a class="header-anchor" href="#model-selection" aria-label="Permalink to &quot;Model selection&quot;">​</a></h2><p>The model dropdown appears in:</p><ul><li>The Script editor&#39;s Revise tab</li><li>AI chat</li><li>The Ideas panel&#39;s inline context hint</li><li>The mobile app&#39;s script detail</li></ul><p>All three providers show in the same dropdown when configured, grouped by provider. Providers that aren&#39;t set up for your account are disabled with a reason (e.g. &quot;No API credits&quot;, &quot;Service unavailable&quot;).</p><h2 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Gemini</th><th>Claude</th><th>Ollama</th></tr></thead><tbody><tr><td>Auth</td><td>API key</td><td>OAuth token</td><td>None (local)</td></tr><tr><td>Streaming</td><td>Yes (token-by-token)</td><td>No (buffered)</td><td>Yes (token-by-token)</td></tr><tr><td>MCP tools</td><td>No</td><td>Yes</td><td>No</td></tr><tr><td>Speed</td><td>Fast</td><td>Multi-turn possible</td><td>Depends on GPU</td></tr><tr><td>Cost</td><td>API credits</td><td>Included with Claude subscription</td><td>Free (your hardware)</td></tr><tr><td>Internet</td><td>Required</td><td>Required</td><td>Not needed after pull</td></tr></tbody></table>`,35)])])}const u=t(l,[["render",o]]);export{k as __pageData,u as default};
